create extension if not exists "pgcrypto";
create table if not exists usuarios (id uuid primary key default gen_random_uuid(), nome text not null, email text unique not null, senha_hash text not null, perfil text not null default 'operador', ativo boolean not null default true, criado_em timestamptz default now());
create table if not exists marcas (id bigint generated always as identity primary key, nome text unique not null, ativo boolean default true);
create table if not exists modelos (id bigint generated always as identity primary key, marca_id bigint not null references marcas(id), nome text not null, ativo boolean default true, unique(marca_id,nome));
create table if not exists servicos (id bigint generated always as identity primary key, nome text unique not null, descricao text, preco numeric(12,2) not null default 0, custo numeric(12,2) not null default 0, ativo boolean default true);
create table if not exists clientes (id bigint generated always as identity primary key, nome text not null, documento text, telefone text, email text, endereco text);
create table if not exists insumos (id bigint generated always as identity primary key, sku text unique not null, nome text not null, unidade text not null default 'UN', estoque numeric(12,3) not null default 0, estoque_minimo numeric(12,3) not null default 0, custo_medio numeric(12,2) not null default 0, preco_venda numeric(12,2) not null default 0, ativo boolean default true);
create table if not exists ordens_servico (id bigint generated always as identity primary key, numero text unique not null, cliente_id bigint references clientes(id), marca_id bigint references marcas(id), modelo_id bigint references modelos(id), equipamento text, numero_serie text, defeito_relatado text, observacao text, situacao text not null default 'Aberta', valor numeric(12,2) default 0, custo numeric(12,2) default 0, criado_em timestamptz default now(), concluido_em timestamptz);
create table if not exists ordem_servicos_itens (id bigint generated always as identity primary key, ordem_id bigint not null references ordens_servico(id) on delete cascade, servico_id bigint references servicos(id), insumo_id bigint references insumos(id), descricao text not null, quantidade numeric(12,3) not null default 1, valor_unitario numeric(12,2) not null default 0, custo_unitario numeric(12,2) not null default 0);
create table if not exists vendas (id bigint generated always as identity primary key, numero text unique not null, cliente_id bigint references clientes(id), subtotal numeric(12,2) not null, desconto numeric(12,2) not null default 0, total numeric(12,2) not null, forma_pagamento text not null, criado_em timestamptz default now());
create table if not exists venda_itens (id bigint generated always as identity primary key, venda_id bigint not null references vendas(id) on delete cascade, insumo_id bigint references insumos(id), servico_id bigint references servicos(id), descricao text not null, quantidade numeric(12,3) not null, valor_unitario numeric(12,2) not null);
create table if not exists movimentos_estoque (id bigint generated always as identity primary key, insumo_id bigint not null references insumos(id), tipo text not null check(tipo in ('ENTRADA','SAIDA','AJUSTE')), quantidade numeric(12,3) not null, motivo text not null, referencia text, criado_em timestamptz default now());
create index if not exists idx_modelos_marca on modelos(marca_id);
create index if not exists idx_os_situacao_data on ordens_servico(situacao, criado_em desc);
create index if not exists idx_movimentos_insumo on movimentos_estoque(insumo_id, criado_em desc);
